export const translations = {
  common: {
    next:     { de: 'Weiter',    en: 'Next'     },
    previous: { de: 'Zurück',   en: 'Back'     },
    submit:   { de: 'Absenden', en: 'Submit'   },
    required: { de: '(Pflichtfeld)', en: '(required)' },
    optional: { de: '(optional)',    en: '(optional)' },
    startOver:{ de: 'Neu starten',   en: 'Start Over' },
    success:  { de: 'Erfolgreich eingereicht!', en: 'Successfully Submitted!' },
    successSub:{ de: 'Ihre Anmeldung wurde übermittelt.', en: 'Your registration has been submitted.' },
    selectPlaceholder: { de: 'Bitte auswählen…', en: 'Please select…' },
  },
  errors: {
    required:    { de: 'Dieses Feld ist erforderlich', en: 'This field is required'  },
    invalidDate: { de: 'Ungültiges Datum',             en: 'Invalid date'            },
  },
  steps: {
    personal: { de: 'Persönliche Daten', en: 'Personal Data' },
    address:  { de: 'Adresse',           en: 'Address'       },
    landlord: { de: 'Vermieter',         en: 'Landlord'      },
    review:   { de: 'Überprüfen',        en: 'Review'        },
  },
};
